import{_ as a,o as e,c as d,a5 as r}from"./chunks/framework.D9Kapg2s.js";const b=JSON.parse('{"title":"翻译配置 · 使用","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/translation-config.md","filePath":"zh/guide/translation-config.md"}'),o={name:"zh/guide/translation-config.md"};function i(l,t,n,h,s,c){return e(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="翻译配置-·-使用" tabindex="-1">翻译配置 · 使用 <a class="header-anchor" href="#翻译配置-·-使用" aria-label="Permalink to &quot;翻译配置 · 使用&quot;">​</a></h1><p>本页说明 <strong>在 Web 界面里如何配置翻译</strong>：AI 后端、提示词、执行配置与执行计划。以步骤与场景为主。</p><div class="tip custom-block"><p class="custom-block-title">第一次使用？</p><p>按 <a href="/zh/guide/getting-started.html">快速开始 · Web</a> 建「单轮翻译 + 内置通用提示词/策略」即可。名词见 <a href="/zh/guide/concepts.html">核心概念</a>。</p><p>字段全集、模板变量、YAML 默认值见 <a href="/zh/guide/translation-config-reference.html">翻译配置 · 参考</a>。流水线原理见 <a href="/zh/guide/pipeline.html">流水线与原理</a>。</p></div><h2 id="四个模块怎么配合" tabindex="-1">四个模块怎么配合 <a class="header-anchor" href="#四个模块怎么配合" aria-label="Permalink to &quot;四个模块怎么配合&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>作用</th><th>界面入口（约）</th></tr></thead><tbody><tr><td><strong>AI 后端</strong></td><td>连哪个模型、Key、Base URL</td><td>AI 后端</td></tr><tr><td><strong>提示词模板</strong></td><td>发给模型的指令（翻译 / 术语提取 / 术语精简）</td><td>翻译配置 · 提示词</td></tr><tr><td><strong>执行配置</strong></td><td>分段、保护、修复、质检、上下文等行为</td><td>翻译配置 · 执行配置</td></tr><tr><td><strong>执行计划</strong></td><td>多轮流水线：每轮用哪个后端、何种模式</td><td>翻译配置 · 执行计划</td></tr></tbody></table><p>点「翻译」时选的是 <strong>执行计划</strong>；计划引用后端 +（翻译轮次上的）提示词与执行配置。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B[AI 后端] --&gt; P[执行计划]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  T[提示词模板] --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E[执行配置] --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P --&gt; J[翻译作业]</span></span></code></pre></div><h2 id="ai-后端" tabindex="-1">AI 后端 <a class="header-anchor" href="#ai-后端" aria-label="Permalink to &quot;AI 后端&quot;">​</a></h2><h3 id="添加后端" tabindex="-1">添加后端 <a class="header-anchor" href="#添加后端" aria-label="Permalink to &quot;添加后端&quot;">​</a></h3><ol><li>打开 <strong>AI 后端</strong>（或设置中的对应入口）</li><li>点击 <strong>添加后端</strong></li><li>选择提供商并填写 API Key 等</li><li>保存</li></ol><table tabindex="0"><thead><tr><th>提供商</th><th>类型</th><th>常用默认模型</th></tr></thead><tbody><tr><td>OpenAI</td><td><code>openai</code></td><td><code>gpt-4o-mini</code></td></tr><tr><td>Anthropic</td><td><code>anthropic</code></td><td><code>claude-sonnet-4-5</code></td></tr><tr><td>Google Gemini</td><td><code>google</code></td><td><code>gemini-2.5-flash</code></td></tr></tbody></table><h3 id="常用选项-界面" tabindex="-1">常用选项（界面） <a class="header-anchor" href="#常用选项-界面" aria-label="Permalink to &quot;常用选项（界面）&quot;">​</a></h3><ul><li><strong>API Key</strong>（必填）</li><li><strong>Model</strong> — 模型名</li><li><strong>Base URL</strong> — 代理或兼容服务（Azure / Ollama / LM Studio 等）</li><li><strong>流式请求</strong> — 仅当上游网关要求 <code>stream:true</code> 时开启；对外仍是完整响应</li><li><strong>每分钟限速</strong> — 避免打满 API 配额（<code>0</code> 表示不限）</li></ul><p>兼容服务示例（OpenAI 类型 + Base URL）：</p><table tabindex="0"><thead><tr><th>服务</th><th>Base URL 示例</th></tr></thead><tbody><tr><td>Ollama</td><td><code>http://localhost:11434/v1</code></td></tr><tr><td>LM Studio</td><td><code>http://localhost:1234/v1</code></td></tr><tr><td>Azure OpenAI</td><td>按资源部署路径填写</td></tr></tbody></table><p>完整字段表见 <a href="/zh/guide/translation-config-reference.html#ai-后端">翻译配置 · 参考 · AI 后端</a>。</p><div class="warning custom-block"><p class="custom-block-title">密钥</p><p>Key 存在本地数据库。CLI 场景优先用环境变量（如 <code>OPENAI_API_KEY</code>），避免写进可提交的配置文件。</p></div><h2 id="提示词模板" tabindex="-1">提示词模板 <a class="header-anchor" href="#提示词模板" aria-label="Permalink to &quot;提示词模板&quot;">​</a></h2><h3 id="何时需要自定义" tabindex="-1">何时需要自定义 <a class="header-anchor" href="#何时需要自定义" aria-label="Permalink to &quot;何时需要自定义&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>通用文档 / 字幕</td><td>直接用内置 <strong>通用提示词</strong></td></tr><tr><td>固定文风、领域口吻、输出约束</td><td>自建翻译提示词</td></tr><tr><td>术语提取质量不满意</td><td>自建术语抽取模板</td></tr><tr><td>术语表过大要清理</td><td>使用术语精简模板（见 <a href="/zh/guide/glossary.html">术语表</a>）</td></tr></tbody></table><h3 id="创建自定义模板" tabindex="-1">创建自定义模板 <a class="header-anchor" href="#创建自定义模板" aria-label="Permalink to &quot;创建自定义模板&quot;">​</a></h3><ol><li>进入 <strong>提示词模板</strong></li><li>选择类型：翻译 / 术语抽取 / 术语精简</li><li><strong>创建模板</strong> → 编辑内容 → 保存</li><li>在执行计划对应轮次中选用该模板</li></ol><p>内置（<code>system</code>）模板不可改删，可复制后改。模板变量与消息协议见 <a href="/zh/guide/translation-config-reference.html#提示词模板">翻译配置 · 参考 · 提示词</a>。</p><h2 id="执行配置" tabindex="-1">执行配置 <a class="header-anchor" href="#执行配置" aria-label="Permalink to &quot;执行配置&quot;">​</a></h2><p>执行配置（Execution Profile）控制「怎么切段、保护什么、如何修响应、是否质检」等。</p><h3 id="创建与选用" tabindex="-1">创建与选用 <a class="header-anchor" href="#创建与选用" aria-label="Permalink to &quot;创建与选用&quot;">​</a></h3><ol><li>进入 <strong>执行配置</strong> → <strong>创建配置</strong></li><li>从内置 <strong>通用策略</strong> 复制或从零调整</li><li>在执行计划的 <strong>翻译轮次</strong> 中引用该配置</li></ol><h3 id="常见调参场景" tabindex="-1">常见调参场景 <a class="header-anchor" href="#常见调参场景" aria-label="Permalink to &quot;常见调参场景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>目标</th><th>建议调整</th></tr></thead><tbody><tr><td>代码/链接被误译</td><td>确认 <strong>内容保护</strong> 开启，规则含 <code>code</code> / <code>link</code> / <code>placeholder</code> / <code>xml</code></td></tr><tr><td>长文前后不连贯</td><td>打开 <strong>上下文窗口</strong>，适当增大 before/after</td></tr><tr><td>译文格式经常坏</td><td>保持 <strong>响应修复</strong> 默认开启</td></tr><tr><td>专业术语要边译边抽</td><td>开启执行配置中的 <strong>内联术语自举</strong>（或改用计划里的提取轮次）</td></tr><tr><td>质检太吵 / 太松</td><td>调整 <strong>质量检测</strong> 长度比等；误报再用裁决轮次降噪</td></tr></tbody></table><p>字段说明与默认 YAML 见 <a href="/zh/guide/translation-config-reference.html#执行配置">翻译配置 · 参考 · 执行配置</a>。行为原理见 <a href="/zh/guide/pipeline.html">流水线与原理</a>。</p><h2 id="执行计划" tabindex="-1">执行计划 <a class="header-anchor" href="#执行计划" aria-label="Permalink to &quot;执行计划&quot;">​</a></h2><p>执行计划把后端、模板、配置串成 <strong>按顺序执行的轮次</strong>。</p><h3 id="轮次模式" tabindex="-1">轮次模式 <a class="header-anchor" href="#轮次模式" aria-label="Permalink to &quot;轮次模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>做什么</th><th>典型位置</th></tr></thead><tbody><tr><td><code>translate</code></td><td>翻译段落</td><td>至少一轮，可多轮做失败回退</td></tr><tr><td><code>extract</code></td><td>从源文抽术语写入术语表</td><td>通常在翻译前</td></tr><tr><td><code>adjudicate</code></td><td>AI 复核规则质检问题，剔除误报</td><td>通常在翻译后</td></tr></tbody></table><p>推荐顺序：<code>extract</code>（可选）→ <code>translate</code>（可多轮）→ <code>adjudicate</code>（可选）。</p><h3 id="最小计划-上手" tabindex="-1">最小计划（上手） <a class="header-anchor" href="#最小计划-上手" aria-label="Permalink to &quot;最小计划（上手）&quot;">​</a></h3><ol><li><strong>创建计划</strong>，命名如「默认翻译」</li><li>添加一轮 <strong>翻译</strong>： <ul><li>后端 = 你刚配的 AI 后端</li><li>提示词 = 内置通用提示词</li><li>执行配置 = 内置通用策略</li><li>批次 / 并发：先用界面默认；撞限速再降并发</li></ul></li><li>保存，创建作业时选它</li></ol><h3 id="进阶组合" tabindex="-1">进阶组合 <a class="header-anchor" href="#进阶组合" aria-label="Permalink to &quot;进阶组合&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>计划怎么搭</th></tr></thead><tbody><tr><td>术语要先建表</td><td>提取轮次 → 翻译轮次</td></tr><tr><td>主模型常失败</td><td>翻译轮次 1（主模型）+ 翻译轮次 2（备用模型/更小批次）</td></tr><tr><td>源语残留误报多</td><td>翻译后加 <strong>质量裁决</strong>，勾选 <code>source_residual</code>（可选 <code>length_ratio</code>）</td></tr><tr><td>日文 HTML 注音</td><td>执行配置开 Ruby；计划可开 Ruby 重试</td></tr></tbody></table><h3 id="创建步骤-完整" tabindex="-1">创建步骤（完整） <a class="header-anchor" href="#创建步骤-完整" aria-label="Permalink to &quot;创建步骤（完整）&quot;">​</a></h3><ol><li><strong>设置 → 执行计划 → 创建计划</strong></li><li>（可选）添加 <strong>提取</strong> 轮次并选术语抽取模板</li><li>添加至少一轮 <strong>翻译</strong></li><li>（可选）添加 <strong>质量裁决</strong></li><li>（可选）配置 Ruby 重试</li><li>保存</li></ol><div class="info custom-block"><p class="custom-block-title">裁决提示词</p><p>质量裁决使用系统内置提示词，<strong>不能</strong>选自定义模板。<code>untranslated</code> / <code>duplicate</code> 为硬规则，不可裁决。</p></div><p>批次、重试、过滤等字段见 <a href="/zh/guide/translation-config-reference.html#执行计划">翻译配置 · 参考 · 执行计划</a>。多轮回退与裁决原理见 <a href="/zh/guide/pipeline.html">流水线与原理</a>。</p><h2 id="术语提取的两种方式" tabindex="-1">术语提取的两种方式 <a class="header-anchor" href="#术语提取的两种方式" aria-label="Permalink to &quot;术语提取的两种方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>在哪里开</th><th>特点</th></tr></thead><tbody><tr><td><strong>提取轮次</strong> <code>extract</code></td><td>执行计划</td><td>独立 LLM 调用，适合译前建表</td></tr><tr><td><strong>内联自举</strong></td><td>执行配置 <code>bootstrap</code></td><td>翻译响应里顺带抽术语，省一次调用</td></tr></tbody></table><p>操作与同步见 <a href="/zh/guide/glossary.html">术语表管理</a>。</p><h2 id="作用域-多用户时" tabindex="-1">作用域（多用户时） <a class="header-anchor" href="#作用域-多用户时" aria-label="Permalink to &quot;作用域（多用户时）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>作用域</th><th>含义</th></tr></thead><tbody><tr><td><code>system</code></td><td>内置，只读</td></tr><tr><td><code>user</code></td><td>仅创建者</td></tr><tr><td><code>org</code></td><td>组织共享（依赖服务器模式 · 预览）</td></tr></tbody></table><p>本地模式只需关心自己的 <code>user</code> 资源与内置 <code>system</code> 模板。</p><h2 id="最佳实践-短" tabindex="-1">最佳实践（短） <a class="header-anchor" href="#最佳实践-短" aria-label="Permalink to &quot;最佳实践（短）&quot;">​</a></h2><ol><li>先跑通最小计划，再加提取/裁决</li><li>专业内容优先维护 <a href="/zh/guide/glossary.html">术语表</a></li><li>保护规则保持开启，避免代码与占位符被译</li><li>并发与批次按 API 限速与模型上下文调整</li><li>质检误报用裁决降噪，硬规则问题仍人工处理</li></ol><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/zh/guide/translation-config-reference.html">翻译配置 · 参考</a> — 字段与模板变量</li><li><a href="/zh/guide/pipeline.html">流水线与原理</a> — 多轮、保护、修复、裁决如何工作</li><li><a href="/zh/guide/glossary.html">术语表管理</a> · <a href="/zh/guide/review.html">翻译审校</a></li><li>CLI 侧配置文件：<a href="/zh/guide/configuration.html">配置文件与环境变量</a></li></ul>`,53)])])}const u=a(o,[["render",i]]);export{b as __pageData,u as default};
